record_types.code:
type DIR_Register
  (As_Array : Boolean := False)
is record
   case As_Array is
      when False =>
         Val : HAL.UInt32;
      when True =>
         Arr : DIR_PIN_Field_Array;
   end case;
end record;

type DIRCLR_Register
  (As_Array : Boolean := False)
